import sys

class Solution:
    def minEatingSpeed(self, piles: list[int], h: int) -> int:
        # binary search on speed k
        left, right = 1, max(piles)
        while left < right:
            mid = (left + right) // 2
            # compute hours needed at speed mid
            hours = 0
            for p in piles:
                hours += (p + mid - 1) // mid  # ceil division
            if hours <= h:
                right = mid
            else:
                left = mid + 1
        return left

