#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int minEatingSpeed(vector<int>& piles, int h) {
        int left = 1;
        int right = *max_element(piles.begin(), piles.end());
        while (left < right) {
            int mid = left + (right - left) / 2;
            long long hours = 0;
            for (int p : piles) {
                hours += (p + mid - 1) / mid; // ceil division
                if (hours > h) break; // early stop
            }
            if (hours <= h) {
                right = mid;
            } else {
                left = mid + 1;
            }
        }
        return left;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> piles(n);
    for (int i = 0; i < n; ++i) cin >> piles[i];
    int h;
    if (!(cin >> h)) return 0;
    Solution sol;
    int ans = sol.minEatingSpeed(piles, h);
    cout << ans << "\n";
    return 0;
}
